class Solution {
public:
    bool canFinish(int numCourses, vector<vector<int>>& prerequisites) {
        vector<bool> visited(numCourses, false);
        for (auto prerequisite : prerequisites) {
            int a = prerequisite[0], b = prerequisite[1];
            if (visited[a] == false && dfs(numCourses, prerequisites, a, b, visited)) {
                return true;
            }
        }
        return false;
    }

    bool dfs(int numCourses, vector<vector<int>>& prerequisites, int a, int b, vector<bool>& visited) {
        visited[a] = true;
        for (int i = 0; i < numCourses; i++) {
            if (visited[i] == false && dfs(numCourses, prerequisites, i, b, visited)) {
                return true;
            }
        }
        visited[b] = true;
        return false;
    }
};
